#!/usr/bin/env node

import { execSync } from 'node:child_process';

import { getRegistryNamespace } from './artifactory.mjs';

function main() {
  const artifactoryToken = process.env.ARTIFACTORY_NPM_TOKEN;
  if (!artifactoryToken) {
    console.error('\n❌ ERROR: ARTIFACTORY_NPM_TOKEN is not set.');
    console.error(
      'Refer to the readme for instructions on setting up Artifactory.\n'
    );
    return;
  }

  const registry = getRegistryNamespace();

  try {
    execSync(
      `npm config set --local ${registry}:_authToken=${artifactoryToken}`,
      {
        stdio: 'inherit',
      }
    );
  } catch (error) {
    console.error('Error setting npm config:', error.message);
    return;
  }
}

main();
